function weightedIntervalMax(intervals) {
  if (!Array.isArray(intervals) || intervals.length === 0) return 0;

  const items = intervals
    .map(([start, end, value]) => ({ start, end, value }))
    .sort((a, b) => a.end - b.end || a.start - b.start);

  const n = items.length;
  // dp[i] = best total value using items[0..i-1]
  const dp = new Array(n + 1).fill(0);

  for (let i = 1; i <= n; i++) {
    const cur = items[i - 1];
    // Best without taking cur
    let best = dp[i - 1];
    // Find latest j (1-based) whose end <= cur.start; touching allowed
    let take = cur.value;
    for (let j = i - 1; j >= 1; j--) {
      if (items[j - 1].end <= cur.start) {
        take += dp[j];
        break;
      }
    }
    dp[i] = Math.max(best, take);
  }

  return dp[n];
}
